10	const countLiveNeighbors = (cell: Cell, cells: Cell[]): number =>
11	  cells.filter((other) => isNeighbor(cell, other)).length;
12	
13	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
14	
15	const deadNeighborCandidates = (cells: Cell[]): Cell[] => {
16	  const candidates: Cell[] = [];
17	  const seen = new Set<string>();
18	  const liveKeys = new Set(cells.map(cellKey));
19	  for (const [x, y] of cells) {
20	    for (let dx = -1; dx <= 1; dx++) {
21	      for (let dy = -1; dy <= 1; dy++) {
22	        if (dx === 0 && dy === 0) continue;
23	        const neighbor: Cell = [x + dx, y + dy];
24	        const key = cellKey(neighbor);
25	        if (liveKeys.has(key) || seen.has(key)) continue;
26	        seen.add(key);
27	        candidates.push(neighbor);
28	      }
29	    }
30	  }
31	  return candidates;
32	};
