34	export const nextGeneration = (cells: Cell[]): Cell[] => {
35	  const survivors = cells.filter((cell) => {
36	    const count = countLiveNeighbors(cell, cells);
37	    return count === 2 || count === 3;
38	  });
39	  const births = deadNeighborCandidates(cells).filter(
40	    (cell) => countLiveNeighbors(cell, cells) === 3
41	  );
42	  return [...survivors, ...births];
43	};
